const input = $input.item.json;

const title = (input['Titel'] || '').trim();
const genre = (input['Genre'] || 'Abenteuer').trim();
const stufe = parseInt((input['Lesestufe'] || '3').toString().replace(/[^0-9]/g, '')) || 3;
const persona = (input['Persona'] || 'lea').trim().toLowerCase();
const description = (input['Kurzbeschreibung'] || '').trim();

// Slug
const umlautMap = { 'ä': 'ae', 'ö': 'oe', 'ü': 'ue', 'ß': 'ss', 'Ä': 'ae', 'Ö': 'oe', 'Ü': 'ue' };
const slug = title.toLowerCase()
  .replace(/[äöüßÄÖÜ]/g, c => umlautMap[c] || c)
  .replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '').replace(/-+/g, '-')
  .substring(0, 60) || 'neue-geschichte';

const stufeData = {
  1: { label: 'Anfänger (Phase 1.0)', regeln: 'Max. 5 Wörter pro Satz. Nur Top-100-Grundwörter. Präsens. SPO-Sätze. Gesamt: 30-50 Wörter.', imageCount: 1 },
  3: { label: 'Mittelstufe (Phase 3.4)', regeln: 'Gesamt: 80-100 Wörter. Konjunktionen erlaubt (weil, aber, denn). Einfache Nebensätze OK. Präteritum.', imageCount: 2 },
  5: { label: 'Profi (Phase 5.3)', regeln: 'Gesamt: 200-300 Wörter. Abstrakta, Gefühle, Innenperspektive. Idiome erlaubt. Tiefe Charakterentwicklung.', imageCount: 4 }
};

const personaMeta = {
  lea:  { name: 'Lea Lesestark',    neurotype: 'Neurotypisch',             imgUrl: 'https://rala84.github.io/lesekumpel/avatars/lea-lesestark.webp',   bio: 'Lea erzählt Geschichten die dich sofort mitreißen. Warm, neugierig, und immer auf Augenhöhe.' },
  timo: { name: 'Timo Taktschritt', neurotype: 'LRS/Legasthenie',          imgUrl: 'https://rala84.github.io/lesekumpel/avatars/timo-taktschritt.webp', bio: 'Timo schreibt im Rhythmus — kurze Wörter, klarer Beat. Lesen fühlt sich an wie Musik hören.' },
  zara: { name: 'Zara Zapp',        neurotype: 'ADHS',                     imgUrl: 'https://rala84.github.io/lesekumpel/avatars/zara-zapp.webp',        bio: 'Zara ist immer in Bewegung! Erster Satz = sofortige Action. Langweile? Keine Chance!' },
  leo:  { name: 'Leo Klartext',     neurotype: 'Autismus-Spektrum',        imgUrl: 'https://rala84.github.io/lesekumpel/avatars/leo-klartext.webp',     bio: 'Leo sagt genau was er meint. Keine Rätsel, keine Metaphern — nur klare, ehrliche Geschichten.' },
  mia:  { name: 'Mia Brücke',       neurotype: 'Deutsch als Zweitsprache', imgUrl: 'https://rala84.github.io/lesekumpel/avatars/mia-bruecke.webp',      bio: 'Mia erklärt die Welt als wäre alles neu. Schwierige Wörter? Erklärt sie einfach!' }
};

const p = personaMeta[persona] || personaMeta.lea;
const s = stufeData[stufe] || stufeData[3];

const userPrompt = `Schreib die Geschichte "${title}" auf Stufe ${stufe} (${s.label}).
Genre: ${genre}
Kurzbeschreibung: ${description || 'Keine Beschreibung angegeben'}

STUFEN-REGELN:
${s.regeln}

SILBENTRENNUNG (PFLICHT):
Trenne jede Silbe mit Bindestrich nach DUDEN: Son-ne, Was-ser, Früh-stück, lau-fen
Einsilbige Wörter bleiben ungeteilt: der, die, das, hat, kam

AUFBAU (diese Labels verwenden):
GESCHICHTE: [vollständiger Text]
ZUSAMMENFASSUNG: [2-3 Sätze]`;

return {
  json: {
    title, genre, stufe, stufeLabel: s.label, persona, description,
    slug, date: new Date().toISOString().split('T')[0],
    personaName: p.name, neurotype: p.neurotype,
    personaImg: p.imgUrl, personaBio: p.bio,
    imageCount: s.imageCount, stufeRegeln: s.regeln, userPrompt
  }
};

const d = $input.item.json;
const { title, description, persona, stufe } = d;

const BLOCKED = ['gewalt', 'waffe', 'sex', 'drogen', 'sterben', 'töten', 'mord'];
const hit = BLOCKED.find(w => (title + ' ' + description).toLowerCase().includes(w));
if (hit) throw new Error(`Inhalt nicht kindgerecht: "${hit}" gefunden`);

const VALID = { lea: [1,3,5], mia: [1,3,5], timo: [3,5], zara: [3,5], leo: [5] };
const allowed = VALID[persona] || [];
if (!allowed.includes(Number(stufe))) {
  throw new Error(`${persona} ist auf Stufe ${stufe} nicht verfügbar. Gültig: Stufen ${JSON.stringify(VALID[persona] || [])}`);
}
return { json: d };

const input = $('Daten vorbereiten').first().json;
const responseText = $input.item.json.text || '';

const storyMatch = responseText.match(/GESCHICHTE:[\s\S]*?(?=ZUSAMMENFASSUNG:|$)/);
const summaryMatch = responseText.match(/ZUSAMMENFASSUNG:[\s\S]*/);

const storyText = storyMatch ? storyMatch[0].replace('GESCHICHTE:', '').trim() : responseText.trim();
const summaryText = summaryMatch ? summaryMatch[0].replace('ZUSAMMENFASSUNG:', '').trim() : storyText.split('\n')[0];
const wordCount = storyText.split(/\s+/).length;

return { json: { ...input, storyText, summaryText, wordCount } };

